const exec = $input.first().json;
const errorMsg = exec.error?.message || 'Unknown error';
const lastNode = exec.execution?.lastNodeExecuted || 'unknown';
const workflowName = exec.workflow?.name || 'unknown';
const n8nVersion = exec.n8nVersion || 'unknown';

// Parse error code from message like "Kie.ai API error (422): ..."
const codeMatch = errorMsg.match(/\((\d+)\)/);
const errorCode = codeMatch ? codeMatch[1] : 'unknown';

return [{
  json: {
    node: lastNode,
    operation: 'unknown',
    errorCode,
    errorMessage: errorMsg.substring(0, 500),
    packageVersion: 'n8n-nodes-kie-pro (local instance)',
    n8nVersion,
    workflowName,
    timestamp: new Date().toISOString(),
    executionId: exec.id,
    workflowId: exec.workflow?.id,
  }
}];
